/**
 * FomaPrint catalog data layer.
 *
 * Product facts (names, SKUs, sizes, prices and product photography) are the
 * real catalog of our supplier/manufacturer, imported from products.json which
 * is generated by .scrape/scrape.py. FOMA FAMILY LLC is an authorized reseller
 * of this catalog. Presentation-only fields that the source feed does not
 * provide (lead time, badges, descriptions and personalization options) are
 * derived deterministically from each SKU so the catalog renders identically
 * on every server/client pass.
 *
 * This module imports the full dataset and must only be used from the server
 * (Server Components, route handlers, metadata). Client components should import
 * types from "@/data/types" and helpers from "@/lib/format".
 */

import rawData from "./products.json";
import { fomaProducts, FOMA_CATEGORY } from "./foma-products";
import type {
  Category,
  IconKey,
  PersonalizationOption,
  Product,
  SearchResult,
  Subcategory,
} from "./types";

export type {
  Category,
  IconKey,
  PersonalizationOption,
  PersonalizationType,
  Product,
  SearchResult,
  Subcategory,
} from "./types";

/* ------------------------------------------------------------------ */
/* Raw dataset shape                                                   */
/* ------------------------------------------------------------------ */

interface RawProduct {
  id: string;
  name: string;
  sku: string;
  size: string | null;
  price: number | null;
  image: string | null;
  imageFull: string | null;
  categoryId: string;
  categorySlug: string;
  categoryName: string;
  subId: string;
  subSlug: string;
  subName: string;
}

interface RawCategory {
  id: string;
  slug: string;
  name: string;
  subcategories: { subId: string; slug: string; name: string; count: number }[];
}

interface RawData {
  source: string;
  scrapedAt: string;
  categories: RawCategory[];
  products: RawProduct[];
}

const data = rawData as unknown as RawData;

